import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface NameIconShopItem {
    id: number;
    key: string; // file key for asset
    price: number;
    owned: boolean;
    equipped: boolean;
}

export class NameIconShopParser implements IMessageParser {
    private _items: NameIconShopItem[] = [];
    private _equippedId = 0;

    flush(): boolean {
        this._items = [];
        this._equippedId = 0;
        return true;
    }

    parse(wrapper: IMessageDataWrapper): boolean {
        const count = wrapper.readInt();
        const items: NameIconShopItem[] = [];
        for (let i = 0; i < count; i++) {
            const id = wrapper.readInt();
            const key = wrapper.readString();
            const price = wrapper.readInt();
            const owned = wrapper.readBoolean();
            const equipped = wrapper.readBoolean();
            items.push({ id, key, price, owned, equipped });
        }
        this._items = items;
        const eq = items.find((i) => i.equipped);
        this._equippedId = eq ? eq.id : 0;

        // Bridge → React (mirror bubbles)
        window.dispatchEvent(
            new CustomEvent('name_icon_shop', {
                detail: {
                    items: items.map((i) => ({
                        iconId: i.id,
                        key: i.key,
                        price: i.price,
                        owned: i.owned,
                        equipped: i.equipped,
                    })),
                    equippedId: this._equippedId,
                },
            })
        );

        return true;
    }

    get items() {
        return this._items;
    }
    get equippedId() {
        return this._equippedId;
    }
}
